import { cn } from '@/utils/cn';
import type { FactoryArg, InputMask } from 'imask';
import IMask from 'imask/holder';
import 'imask/masked/number';
import 'imask/masked/pattern';
import X from 'lucide-solid/icons/x';
import {
  Component,
  createEffect,
  createUniqueId,
  mergeProps,
  on,
  onCleanup,
  onMount,
  Show,
} from 'solid-js';
import type { InputTextProps } from '../input.types';
import { DEFAULT_PROPS, inputTextVariants } from '../input.utils';

export const InputText: Component<InputTextProps> = (p => {
  p = mergeProps({ ...DEFAULT_PROPS, id: createUniqueId() }, p);
  let maskInstance: InputMask<FactoryArg> | undefined;
  let inputRef: HTMLInputElement | undefined;
  const focusInput = () => {
    inputRef?.focus();
  };
  let maskAcceptEvent: any = null;
  createEffect(
    on(
      () => p.maskOptions,
      value => maskInstance && value && maskInstance.updateOptions(value),
      { defer: true },
    ),
  );
  onMount(() => {
    if (inputRef && p.maskOptions) {
      maskInstance = IMask(inputRef, p.maskOptions);

      maskAcceptEvent = (e: InputEvent) => {
        p.onChange && p.onChange(maskInstance?.value ?? '', e);
        p.maskOptions?.onAccept &&
          p.maskOptions?.onAccept(maskInstance?.value, maskInstance?.unmaskedValue);
      };
      maskInstance.on('accept', maskAcceptEvent);
      if (typeof p.maskOptions.onAccept === 'function') {
      }
    }
  });
  onCleanup(function destroyTextMask() {
    if (maskInstance) {
      maskAcceptEvent && maskInstance.off('accept', maskAcceptEvent);
      maskInstance.destroy();
    }
  });
  const handleClear = (e: MouseEvent) => {
    e.stopPropagation();
    if (maskInstance) {
      maskInstance.value = '';
      maskInstance.updateValue();
    } else if (inputRef) {
      inputRef.value = '';
    }
    p.onInput?.('', undefined as any);
    p.onChange?.('', undefined as any);
    inputRef?.focus();
  };
  return (
    <div
      tabIndex={-1}
      class={cn(
        'it01',
        `input-${p.type}`,
        inputTextVariants({ color: p.color, size: p.size, variant: p.variant }),
        p.class?.root,
        p.disabled && 'border-c5 pointer-events-none',
      )}
      onClick={focusInput}
    >
      {p.prefixIcon}
      <input
        id={p.id}
        ref={inputRef}
        type={p.type || 'text'}
        data-type={p.typeOrigin}
        value={p.value ?? ''}
        placeholder={p.placeholder}
        class={cn('text-c2 grow', p.class?.input)}
        onBlur={e => p.onBlur?.(e.currentTarget.value, e)}
        onChange={e => p.onChange?.(e.currentTarget.value, e)}
        onInput={e => p.onInput?.(e.currentTarget.value, e)}
        onKeyDown={e => {
          if (e.key === 'Enter' || e.keyCode === 13) {
            e.preventDefault();
            p.onPressEnter?.(e.currentTarget.value, e);
          }
        }}
        disabled={p.disabled}
      />
      <Show when={p.allowClear || p.suffixIcon}>
        <div class="it05">
          {p.allowClear && (
            <div class="it03" onClick={handleClear}>
              <X class="m-auto size-2" />
            </div>
          )}
          {p.suffixIcon && <div class="it04">{p.suffixIcon}</div>}
        </div>
      </Show>
    </div>
  );
}) as Component<InputTextProps>;
